def compute_user_features(orders: pd.DataFrame, reference_date: pd.Timestamp) -> pd.DataFrame:
    """Aggregate per-user order features as of reference_date."""
    return orders[orders['order_date'] <= reference_date].groupby('user_id').agg(
        total_revenue=('revenue', 'sum'),
        order_count=('order_id', 'nunique'),
    ).reset_index()

